// // This D flip-flop latches the input D only when the clock is low and the enable signal is low.
module clock_gated_dff (
    input wire clk,
    input wire enable,
    input wire d,
    output reg q
);

always @(posedge clk) begin
    if (enable) begin
        q <= d;
    end
    // When clock is low or enable is low, the output holds its previous value
end

endmodule
